import { SamplingTraceType } from '../span/types';
export interface ConfigChangedEvent {
    namespace: string;
    timestamp: number;
    config: any;
}
export interface GlobalTracerConfig {
    /**
     * 全局总开关
     */
    enableTrace: boolean;
    /**
     * PostTrace是否生效
     */
    enablePostTrace: boolean;
    /**
     * 根据header进行染色是否生效
     */
    enableDyedHeader: boolean;
    /**
     * 是否主动采样
     */
    enableSampling: boolean;
    /**
     * 是否针对服务进行全量上报 span
     */
    enableReportTotalSpan: boolean;
    /**
     * 对于 Span Metrics 的级别控制
     */
    spanMetricsLevel: number;
    /**
     * 对于 Custom Metrics 的界别控制
     */
    customMetricsLevel: number;
    /**
     * 轻量模式控制, component -> option
     */
    lightModeByComponent?: {
        [key: string]: boolean;
    };
    /**
     * 全局轻量控制模式
     */
    rootLightModeByComponent?: {
        [key: string]: boolean;
    };
    /**
     * 旧版指标控制, component -> option
     */
    disableThriftStyleMetricsByComponent?: {
        [key: string]: boolean;
    };
    /**
     * 全局旧版指标控制模式
     */
    rootDisableThriftStyleMetricsByComponent?: {
        [key: string]: boolean;
    };
}
export interface CBConfig {
    /**
     * 单个transaction中span个数上限
     */
    maxSpanCountInTxn: number;
    /**
     * 单个transaction/span/event/metrics中tagKv上限
     */
    maxTagKVCountInObj: number;
    /**
     * 单个span中event个数上限
     */
    maxEventCountInSpan: number;
    /**
     * 单个span中metrics个数上限
     */
    maxCustomMetricCountInSpan: number;
    /**
     * 单个tagKv中value的长度上限
     */
    maxTagValueLen: number;
    /**
     * 单个event中data的长度上限
     */
    maxEventDataLen: number;
    /**
     * 单个transaction序列化后大小上限(byte)
     */
    maxTxnDataLen: number;
    /**
     * Txn各接口采样速率熔断值
     */
    maxTxnSamplingRatePerOperation: number;
    /**
     * PostTrace各接口采样速率熔断值
     */
    maxPostTraceSamplingRatePerOperation: number;
    /**
     * Dyeing 各接口采样速率熔断值
     */
    maxDyeingSamplingRatePerOperation: number;
    /**
     * PostTrace 细分限流配置
     */
    maxPostTraceSamplingDetailStrategies?: DetailSamplingPostTraceParam[];
}
export interface SamplerConfig {
    /**
     * 采样器最大操作限制
     */
    samplerMaxOperationCount: number;
    /**
     * 默认采样策略
     */
    defaultStrategy: SamplingParam;
    /**
     * 细分条件采样策略
     */
    detailStrategies?: DetailSamplingParam[];
    /**
     * 条件过滤器
     */
    conditionSamplingFilters?: ConditionSamplingFilter[];
    /**
     * lower bound 采样器过期时间
     */
    lowerBoundSamplerExpireSecond: number;
}
export interface SamplingParam {
    /**
     * 采样器类型
     */
    samplingMode: string;
    /**
     * 概率采样器采样率
     */
    samplingRateProbability: number;
    /**
     * 自适应采样器每分钟采样数
     */
    samplingCountPerMinAdaptive: number;
}
export interface DetailSamplingParam {
    condition: DetailSamplingCondition;
    strategy: {
        /**
         * 采样器类型
         */
        sampling_mode: string;
        /**
         * 概率采样器采样率
         */
        sampling_rate_probability: number;
        /**
         * 自适应采样器每分钟采样数
         */
        sampling_count_per_min_adaptive: number;
    };
}
interface DetailSamplingCondition {
    clusters: string[];
    methods: string[];
    idcs: string[];
    stages: string[];
}
export interface DetailSamplingPostTraceParam {
    spanType: string;
    spanName: string;
    thresholdPerMin: number;
}
export interface ConditionSamplingFilter {
    name: string;
    spanType: string;
    conditionMetas: ConditionSamplingMeta[];
    samplingType: SamplingTraceType;
    and: boolean;
}
export interface ConditionSamplingMeta {
    param: string;
    symbol: string;
    value: string;
}
export {};
